+            dropped += 1;
+            continue;
+        }
+
+        if is_routine_retry_narration(turn, &normalized) {
+            dropped += 1;
+            continue;
+        }
+
+        if let Some(previous_sequence) = seen_signatures.get(&signature) {
+            if is_repeated_state_check(turn) || turn.role == SessionRole::Tool {
+                let _ = previous_sequence;
+                dropped += 1;
